import * as React from "react";
import { cx } from "../utils";
import { X } from "../icons";

/* ============================================================
   Tooltip
   ============================================================ */
export interface TooltipProps {
  label: React.ReactNode;
  children: React.ReactNode;
  className?: string;
}
/** Hover/focus tooltip. Wraps a single focusable child. */
export function Tooltip({ label, children, className }: TooltipProps) {
  return (
    <span className={cx("pui-tooltip", className)}>
      {children}
      <span role="tooltip" className="pui-tooltip__bubble">
        {label}
      </span>
    </span>
  );
}

/* ============================================================
   Hook: close on outside click / Escape
   ============================================================ */
function useDismiss(open: boolean, onClose: () => void) {
  const ref = React.useRef<HTMLDivElement>(null);
  React.useEffect(() => {
    if (!open) return;
    const onClick = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) onClose();
    };
    const onKey = (e: KeyboardEvent) => e.key === "Escape" && onClose();
    document.addEventListener("mousedown", onClick);
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("mousedown", onClick);
      document.removeEventListener("keydown", onKey);
    };
  }, [open, onClose]);
  return ref;
}

/* ============================================================
   DropdownMenu
   ============================================================ */
export interface MenuItem {
  label: React.ReactNode;
  icon?: React.ReactNode;
  onSelect?: () => void;
  tone?: "default" | "danger";
}
export interface DropdownMenuProps {
  trigger: React.ReactNode;
  children?: React.ReactNode;
  items?: MenuItem[];
  align?: "start" | "end";
  className?: string;
}
/**
 * Click-to-open menu. Provide `items` for a simple list, or `children`
 * for custom content. Closes on outside click and Escape.
 */
export function DropdownMenu({ trigger, children, items, align = "start", className }: DropdownMenuProps) {
  const [open, setOpen] = React.useState(false);
  const ref = useDismiss(open, () => setOpen(false));
  return (
    <div className={cx("pui-menu", className)} ref={ref}>
      <span onClick={() => setOpen((o) => !o)}>{trigger}</span>
      {open && (
        <div className="pui-menu__panel" data-align={align} role="menu">
          {items
            ? items.map((item, i) => (
                <button
                  key={i}
                  type="button"
                  role="menuitem"
                  className="pui-menu__item"
                  data-tone={item.tone === "danger" ? "danger" : undefined}
                  onClick={() => {
                    item.onSelect?.();
                    setOpen(false);
                  }}
                >
                  {item.icon}
                  {item.label}
                </button>
              ))
            : children}
        </div>
      )}
    </div>
  );
}

export function MenuSeparator() {
  return <div className="pui-menu__sep" />;
}

/* ============================================================
   Modal
   ============================================================ */
export interface ModalProps {
  open: boolean;
  onClose: () => void;
  title?: React.ReactNode;
  children?: React.ReactNode;
  footer?: React.ReactNode;
  /** Decorative icon shown beside the title. */
  icon?: React.ReactNode;
}
/** Overlay dialog. Closes on backdrop click and Escape. */
export function Modal({ open, onClose, title, children, footer, icon }: ModalProps) {
  React.useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => e.key === "Escape" && onClose();
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [open, onClose]);

  if (!open) return null;
  return (
    <div className="pui-overlay" onClick={onClose}>
      <div className="pui-dialog" role="dialog" aria-modal="true" onClick={(e) => e.stopPropagation()}>
        <div className="pui-dialog__head">
          <div style={{ display: "flex", gap: 13, alignItems: "flex-start" }}>
            {icon}
            {title && <div className="pui-dialog__title">{title}</div>}
          </div>
          <button type="button" className="pui-dialog__close" aria-label="Close" onClick={onClose}>
            <X style={{ width: 20, height: 20 }} />
          </button>
        </div>
        {children && <div className="pui-dialog__body">{children}</div>}
        {footer && <div className="pui-dialog__footer">{footer}</div>}
      </div>
    </div>
  );
}
