import * as React from "react";
import { cx, initials as toInitials } from "../utils";
import { X } from "../icons";

export type Tone = "neutral" | "green" | "amber" | "red" | "blue" | "accent";

/* ---------------- Badge ---------------- */
export interface BadgeProps extends React.HTMLAttributes<HTMLSpanElement> {
  tone?: Tone;
  solid?: boolean;
  dot?: boolean;
}
export function Badge({ tone = "neutral", solid, dot, className, children, ...props }: BadgeProps) {
  return (
    <span
      className={cx("pui-badge", className)}
      data-tone={tone === "neutral" ? undefined : tone}
      data-solid={solid || undefined}
      {...props}
    >
      {dot && <span className="pui-badge__dot" />}
      {children}
    </span>
  );
}

/* ---------------- Tag (removable) ---------------- */
export interface TagProps extends React.HTMLAttributes<HTMLSpanElement> {
  onRemove?: () => void;
}
export function Tag({ onRemove, className, children, ...props }: TagProps) {
  return (
    <span className={cx("pui-tag", className)} {...props}>
      {children}
      {onRemove && (
        <button type="button" className="pui-tag__close" aria-label="Remove" onClick={onRemove}>
          <X />
        </button>
      )}
    </span>
  );
}

/* ---------------- Avatar ---------------- */
export type AvatarSize = "sm" | "md" | "lg";
export interface AvatarProps extends React.HTMLAttributes<HTMLSpanElement> {
  name: string;
  src?: string;
  size?: AvatarSize;
  tone?: "accent" | "blue" | "green" | "amber";
  status?: "online" | "busy" | "away";
}
export function Avatar({ name, src, size = "md", tone = "accent", status, className, ...props }: AvatarProps) {
  return (
    <span
      className={cx("pui-avatar", className)}
      data-size={size}
      data-tone={tone === "accent" ? undefined : tone}
      title={name}
      {...props}
    >
      {src ? <img src={src} alt={name} /> : toInitials(name)}
      {status && <span className="pui-avatar__status" data-status={status} />}
    </span>
  );
}

export interface AvatarGroupProps {
  /** Avatar elements. */
  children: React.ReactNode;
  /** Show at most this many, collapsing the rest into a "+N". */
  max?: number;
  size?: AvatarSize;
  className?: string;
}
export function AvatarGroup({ children, max, size = "md", className }: AvatarGroupProps) {
  const items = React.Children.toArray(children);
  const shown = max ? items.slice(0, max) : items;
  const extra = max ? items.length - shown.length : 0;
  return (
    <div className={cx("pui-avatar-group", className)}>
      {shown}
      {extra > 0 && (
        <span className="pui-avatar pui-avatar-group__more" data-size={size}>
          +{extra}
        </span>
      )}
    </div>
  );
}

/* ---------------- Card ---------------- */
export interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  padded?: boolean;
}
export function Card({ padded = true, className, children, ...props }: CardProps) {
  return (
    <div className={cx("pui-card", padded && "pui-card--pad", className)} {...props}>
      {children}
    </div>
  );
}

/* ---------------- StatCard ---------------- */
export interface StatCardProps {
  label: React.ReactNode;
  value: React.ReactNode;
  delta?: { value: React.ReactNode; direction: "up" | "down" };
  className?: string;
}
export function StatCard({ label, value, delta, className }: StatCardProps) {
  return (
    <div className={cx("pui-stat", className)}>
      <div className="pui-stat__label">{label}</div>
      <div className="pui-stat__value">{value}</div>
      {delta && (
        <div className="pui-stat__delta" data-dir={delta.direction}>
          {delta.direction === "up" ? "▲" : "▼"} {delta.value}
        </div>
      )}
    </div>
  );
}

/* ---------------- Progress ---------------- */
export interface ProgressProps extends React.HTMLAttributes<HTMLDivElement> {
  /** 0–100. Omit for an indeterminate bar. */
  value?: number;
}
export function Progress({ value, className, ...props }: ProgressProps) {
  const indeterminate = value == null;
  return (
    <div
      className={cx("pui-progress", className)}
      data-indeterminate={indeterminate || undefined}
      role="progressbar"
      aria-valuenow={indeterminate ? undefined : value}
      aria-valuemin={0}
      aria-valuemax={100}
      {...props}
    >
      <div className="pui-progress__bar" style={indeterminate ? undefined : { width: `${value}%` }} />
    </div>
  );
}

/* ---------------- Spinner ---------------- */
export function Spinner({ size = 30, className, style, ...props }: { size?: number } & React.HTMLAttributes<HTMLSpanElement>) {
  return <span role="status" aria-label="Loading" className={cx("pui-spinner", className)} style={{ width: size, height: size, ...style }} {...props} />;
}

/* ---------------- Skeleton ---------------- */
export function Skeleton({ width, height = 11, className, style, ...props }: { width?: number | string; height?: number | string } & React.HTMLAttributes<HTMLDivElement>) {
  return <div className={cx("pui-skeleton", className)} style={{ width, height, ...style }} {...props} />;
}

/* ---------------- EmptyState ---------------- */
export interface EmptyStateProps {
  icon?: React.ReactNode;
  title: React.ReactNode;
  description?: React.ReactNode;
  action?: React.ReactNode;
  className?: string;
}
export function EmptyState({ icon, title, description, action, className }: EmptyStateProps) {
  return (
    <div className={cx("pui-empty", className)}>
      {icon && <span className="pui-empty__icon">{icon}</span>}
      <div className="pui-empty__title">{title}</div>
      {description && <div className="pui-empty__desc">{description}</div>}
      {action && <div style={{ marginTop: 10 }}>{action}</div>}
    </div>
  );
}
