import * as React from "react";
import { cx } from "../utils";
import { X, Check } from "../icons";

/* ============================================================
   Separator
   ============================================================ */
export interface SeparatorProps extends React.HTMLAttributes<HTMLDivElement> {
  orientation?: "horizontal" | "vertical";
}
export function Separator({ orientation = "horizontal", className, ...props }: SeparatorProps) {
  return (
    <div
      role="separator"
      aria-orientation={orientation}
      data-orientation={orientation}
      className={cx("pui-separator", className)}
      {...props}
    />
  );
}

/* ============================================================
   Kbd
   ============================================================ */
export function Kbd({ children, className }: { children: React.ReactNode; className?: string }) {
  return <kbd className={cx("pui-kbd", className)}>{children}</kbd>;
}

/* ============================================================
   Link
   ============================================================ */
export interface LinkProps extends React.AnchorHTMLAttributes<HTMLAnchorElement> {
  external?: boolean;
}
export function Link({ external, className, children, ...props }: LinkProps) {
  return (
    <a
      className={cx("pui-link", className)}
      {...(external ? { target: "_blank", rel: "noreferrer" } : {})}
      {...props}
    >
      {children}
    </a>
  );
}

/* ============================================================
   close-on-outside-click / Escape hook
   ============================================================ */
function useDismiss(open: boolean, onClose: () => void) {
  const ref = React.useRef<HTMLDivElement>(null);
  React.useEffect(() => {
    if (!open) return;
    const onClick = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) onClose();
    };
    const onKey = (e: KeyboardEvent) => e.key === "Escape" && onClose();
    document.addEventListener("mousedown", onClick);
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("mousedown", onClick);
      document.removeEventListener("keydown", onKey);
    };
  }, [open, onClose]);
  return ref;
}

/* ============================================================
   Popover
   ============================================================ */
export interface PopoverProps {
  trigger: React.ReactNode;
  children: React.ReactNode;
  align?: "start" | "end";
  className?: string;
}
export function Popover({ trigger, children, align = "start", className }: PopoverProps) {
  const [open, setOpen] = React.useState(false);
  const ref = useDismiss(open, () => setOpen(false));
  return (
    <div className={cx("pui-menu", className)} ref={ref}>
      <span onClick={() => setOpen((o) => !o)}>{trigger}</span>
      {open && (
        <div className="pui-popover" data-align={align} role="dialog">
          {children}
        </div>
      )}
    </div>
  );
}

/* ============================================================
   Drawer (side sheet)
   ============================================================ */
export interface DrawerProps {
  open: boolean;
  onClose: () => void;
  side?: "left" | "right";
  title?: React.ReactNode;
  children?: React.ReactNode;
  footer?: React.ReactNode;
}
export function Drawer({ open, onClose, side = "right", title, children, footer }: DrawerProps) {
  React.useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => e.key === "Escape" && onClose();
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [open, onClose]);

  if (!open) return null;
  return (
    <div className="pui-drawer-overlay" onClick={onClose}>
      <div className="pui-drawer" data-side={side} role="dialog" aria-modal="true" onClick={(e) => e.stopPropagation()}>
        <div className="pui-drawer__head">
          {title && <div className="pui-drawer__title">{title}</div>}
          <button type="button" className="pui-dialog__close" aria-label="Close" onClick={onClose}>
            <X style={{ width: 20, height: 20 }} />
          </button>
        </div>
        <div className="pui-drawer__body">{children}</div>
        {footer && <div className="pui-drawer__footer">{footer}</div>}
      </div>
    </div>
  );
}

/* ============================================================
   ToggleGroup (single-select)
   ============================================================ */
export interface ToggleOption {
  value: string;
  label: React.ReactNode;
  icon?: React.ReactNode;
}
export interface ToggleGroupProps {
  options: ToggleOption[];
  value: string;
  onValueChange: (value: string) => void;
  className?: string;
}
export function ToggleGroup({ options, value, onValueChange, className }: ToggleGroupProps) {
  return (
    <div className={cx("pui-toggle-group", className)} role="group">
      {options.map((o) => (
        <button
          key={o.value}
          type="button"
          aria-pressed={value === o.value}
          data-active={value === o.value || undefined}
          className="pui-toggle"
          onClick={() => onValueChange(o.value)}
        >
          {o.icon}
          {o.label}
        </button>
      ))}
    </div>
  );
}

/* ============================================================
   Stepper
   ============================================================ */
export interface Step {
  label: React.ReactNode;
  description?: React.ReactNode;
}
export interface StepperProps {
  steps: Step[];
  /** Zero-based index of the active step. Earlier steps render as complete. */
  current: number;
  className?: string;
}
export function Stepper({ steps, current, className }: StepperProps) {
  return (
    <ol className={cx("pui-stepper", className)}>
      {steps.map((s, i) => {
        const state = i < current ? "done" : i === current ? "current" : "upcoming";
        return (
          <li key={i} className="pui-step" data-state={state}>
            <span className="pui-step__marker">{i < current ? <Check /> : i + 1}</span>
            <span className="pui-step__body">
              <span className="pui-step__label">{s.label}</span>
              {s.description && <span className="pui-step__desc">{s.description}</span>}
            </span>
          </li>
        );
      })}
    </ol>
  );
}

/* ============================================================
   CodeBlock
   ============================================================ */
export interface CodeBlockProps {
  code: string;
  filename?: React.ReactNode;
  className?: string;
}
export function CodeBlock({ code, filename, className }: CodeBlockProps) {
  return (
    <div className={cx("pui-code", className)}>
      {filename && <div className="pui-code__bar">{filename}</div>}
      <pre className="pui-code__pre">
        <code>{code}</code>
      </pre>
    </div>
  );
}

/* ============================================================
   List / ListItem
   ============================================================ */
export function List({ children, className }: { children: React.ReactNode; className?: string }) {
  return <ul className={cx("pui-list", className)}>{children}</ul>;
}
export function ListItem({ children, className, ...props }: React.LiHTMLAttributes<HTMLLIElement>) {
  return (
    <li className={cx("pui-list-item", className)} {...props}>
      {children}
    </li>
  );
}
