import * as React from "react";
import { Sun, Moon } from "./icons";
import { cx } from "./utils";

export type Theme = "light" | "dark";

interface ThemeContextValue {
  theme: Theme;
  setTheme: (t: Theme) => void;
  toggle: () => void;
}

const ThemeContext = React.createContext<ThemeContextValue | null>(null);

export interface ThemeProviderProps {
  children: React.ReactNode;
  /** Initial theme when nothing is stored. Default "light". */
  defaultTheme?: Theme;
  /** localStorage key for persistence. Default "pui-theme". Pass null to disable. */
  storageKey?: string | null;
  /** Element to stamp `data-theme` on. Default document.documentElement. */
  attributeTarget?: "html" | "self";
}

/**
 * Wrap your app once. Sets `data-theme` on <html> (or a wrapper div) and
 * persists the choice. Read/control via the `useTheme()` hook.
 */
export function ThemeProvider({
  children,
  defaultTheme = "light",
  storageKey = "pui-theme",
  attributeTarget = "html",
}: ThemeProviderProps) {
  const [theme, setThemeState] = React.useState<Theme>(defaultTheme);

  React.useEffect(() => {
    if (storageKey) {
      const stored = window.localStorage.getItem(storageKey) as Theme | null;
      if (stored === "light" || stored === "dark") setThemeState(stored);
    }
  }, [storageKey]);

  React.useEffect(() => {
    if (attributeTarget === "html") {
      document.documentElement.setAttribute("data-theme", theme);
    }
    if (storageKey) window.localStorage.setItem(storageKey, theme);
  }, [theme, attributeTarget, storageKey]);

  const value = React.useMemo<ThemeContextValue>(
    () => ({
      theme,
      setTheme: setThemeState,
      toggle: () => setThemeState((t) => (t === "light" ? "dark" : "light")),
    }),
    [theme],
  );

  return (
    <ThemeContext.Provider value={value}>
      {attributeTarget === "self" ? <div data-theme={theme}>{children}</div> : children}
    </ThemeContext.Provider>
  );
}

export function useTheme(): ThemeContextValue {
  const ctx = React.useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme must be used within a <ThemeProvider>");
  return ctx;
}

/** Drop-in icon button that flips the theme. */
export function ThemeToggle({ className, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  const { theme, toggle } = useTheme();
  return (
    <button
      type="button"
      aria-label="Toggle color theme"
      onClick={toggle}
      className={cx("pui-btn", "pui-btn--secondary", "pui-btn--icon", className)}
      {...props}
    >
      {theme === "light" ? <Moon className="pui-icon" /> : <Sun className="pui-icon" />}
    </button>
  );
}
