import * as React from "react";
import { cx } from "../utils";
import { ChevronDown } from "../icons";

interface AccordionContextValue {
  isOpen: (value: string) => boolean;
  toggle: (value: string) => void;
}
const AccordionContext = React.createContext<AccordionContextValue | null>(null);

export interface AccordionProps {
  children: React.ReactNode;
  /** "single" (default) collapses others; "multiple" allows many open. */
  type?: "single" | "multiple";
  defaultValue?: string | string[];
  className?: string;
}

/**
 * Collapsible disclosure list.
 * @example
 * <Accordion defaultValue="a">
 *   <AccordionItem value="a" title="How is usage metered?">…</AccordionItem>
 *   <AccordionItem value="b" title="Can I rotate keys?">…</AccordionItem>
 * </Accordion>
 */
export function Accordion({ children, type = "single", defaultValue, className }: AccordionProps) {
  const [open, setOpen] = React.useState<string[]>(
    defaultValue == null ? [] : Array.isArray(defaultValue) ? defaultValue : [defaultValue],
  );

  const value = React.useMemo<AccordionContextValue>(
    () => ({
      isOpen: (v) => open.includes(v),
      toggle: (v) =>
        setOpen((prev) => {
          const has = prev.includes(v);
          if (type === "single") return has ? [] : [v];
          return has ? prev.filter((x) => x !== v) : [...prev, v];
        }),
    }),
    [open, type],
  );

  return (
    <div className={cx("pui-accordion", className)}>
      <AccordionContext.Provider value={value}>{children}</AccordionContext.Provider>
    </div>
  );
}

export interface AccordionItemProps {
  value: string;
  title: React.ReactNode;
  children: React.ReactNode;
}
export function AccordionItem({ value, title, children }: AccordionItemProps) {
  const ctx = React.useContext(AccordionContext);
  if (!ctx) throw new Error("AccordionItem must be used within <Accordion>");
  const open = ctx.isOpen(value);
  return (
    <div className="pui-accordion__item" data-open={open || undefined}>
      <button
        type="button"
        className="pui-accordion__trigger"
        aria-expanded={open}
        onClick={() => ctx.toggle(value)}
      >
        {title}
        <ChevronDown className="pui-accordion__chevron" />
      </button>
      {open && <div className="pui-accordion__panel">{children}</div>}
    </div>
  );
}
