import * as React from "react";
import { cx } from "../utils";
import { Check, ChevronDown, Search as SearchIcon, XCircle } from "../icons";

/* ---------------- Field wrapper ---------------- */
export interface FieldProps {
  label?: React.ReactNode;
  hint?: React.ReactNode;
  error?: React.ReactNode;
  htmlFor?: string;
  children: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
}

/** Labelled wrapper: renders label, control, and hint/error text. */
export function Field({ label, hint, error, htmlFor, children, className, style }: FieldProps) {
  return (
    <div className={cx("pui-field", className)} style={style}>
      {label && (
        <label className="pui-label" htmlFor={htmlFor}>
          {label}
        </label>
      )}
      {children}
      {error ? (
        <span className="pui-error">
          <XCircle style={{ width: 13, height: 13 }} />
          {error}
        </span>
      ) : (
        hint && <span className="pui-hint">{hint}</span>
      )}
    </div>
  );
}

/* ---------------- Input ---------------- */
export interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  invalid?: boolean;
}
export const Input = React.forwardRef<HTMLInputElement, InputProps>(function Input(
  { invalid, className, ...props },
  ref,
) {
  return (
    <input
      ref={ref}
      aria-invalid={invalid || undefined}
      className={cx("pui-input", invalid && "pui-input--invalid", className)}
      {...props}
    />
  );
});

/** Input with a leading search glyph. */
export const SearchInput = React.forwardRef<HTMLInputElement, InputProps>(function SearchInput(
  { className, ...props },
  ref,
) {
  return (
    <span className="pui-input-wrap">
      <SearchIcon className="pui-input-wrap__icon" />
      <Input ref={ref} className={className} {...props} />
    </span>
  );
});

/* ---------------- Textarea ---------------- */
export interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  invalid?: boolean;
}
export const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(function Textarea(
  { invalid, className, rows = 3, ...props },
  ref,
) {
  return (
    <textarea
      ref={ref}
      rows={rows}
      aria-invalid={invalid || undefined}
      className={cx("pui-textarea", invalid && "pui-textarea--invalid", className)}
      {...props}
    />
  );
});

/* ---------------- Select (native, styled) ---------------- */
export interface SelectProps extends React.SelectHTMLAttributes<HTMLSelectElement> {
  options?: Array<{ label: string; value: string }>;
}
export const Select = React.forwardRef<HTMLSelectElement, SelectProps>(function Select(
  { options, className, children, ...props },
  ref,
) {
  return (
    <span className="pui-select-wrap">
      <select ref={ref} className={cx("pui-select", className)} {...props}>
        {options
          ? options.map((o) => (
              <option key={o.value} value={o.value}>
                {o.label}
              </option>
            ))
          : children}
      </select>
      <ChevronDown className="pui-select-wrap__caret" />
    </span>
  );
});

/* ---------------- Checkbox ---------------- */
export interface CheckboxProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, "type"> {
  label?: React.ReactNode;
}
export const Checkbox = React.forwardRef<HTMLInputElement, CheckboxProps>(function Checkbox(
  { label, disabled, className, ...props },
  ref,
) {
  return (
    <label className={cx("pui-checkbox", disabled && "pui-checkbox--disabled", className)}>
      <input ref={ref} type="checkbox" disabled={disabled} {...props} />
      <span className="pui-checkbox__box">
        <Check />
      </span>
      {label}
    </label>
  );
});

/* ---------------- Switch ---------------- */
export interface SwitchProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, "type"> {}
export const Switch = React.forwardRef<HTMLInputElement, SwitchProps>(function Switch(
  { className, ...props },
  ref,
) {
  return (
    <label className={cx("pui-switch", className)}>
      <input ref={ref} type="checkbox" role="switch" {...props} />
      <span className="pui-switch__track" />
    </label>
  );
});

/* ---------------- RadioGroup ---------------- */
export interface RadioOption {
  value: string;
  title: React.ReactNode;
  description?: React.ReactNode;
}
export interface RadioGroupProps {
  name: string;
  value: string;
  onValueChange: (value: string) => void;
  options: RadioOption[];
  className?: string;
}
/** Card-style radio group. Controlled via `value` / `onValueChange`. */
export function RadioGroup({ name, value, onValueChange, options, className }: RadioGroupProps) {
  return (
    <div className={cx("pui-radio-group", className)} role="radiogroup">
      {options.map((o) => (
        <label key={o.value} className="pui-radio-card">
          <input
            type="radio"
            name={name}
            value={o.value}
            checked={value === o.value}
            onChange={() => onValueChange(o.value)}
          />
          <span className="pui-radio-card__dot" />
          <span>
            <span className="pui-radio-card__title">{o.title}</span>
            {o.description && <span className="pui-radio-card__desc">{o.description}</span>}
          </span>
        </label>
      ))}
    </div>
  );
}

/* ---------------- Slider ---------------- */
export interface SliderProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, "type" | "value" | "onChange"> {
  value: number;
  min?: number;
  max?: number;
  onValueChange: (value: number) => void;
}
export function Slider({ value, min = 0, max = 100, onValueChange, className, ...props }: SliderProps) {
  const pct = ((value - min) / (max - min)) * 100;
  return (
    <div className={cx("pui-slider", className)}>
      <div className="pui-slider__row">
        <div className="pui-slider__track" />
        <div className="pui-slider__fill" style={{ width: `${pct}%` }} />
        <input
          type="range"
          min={min}
          max={max}
          value={value}
          onChange={(e) => onValueChange(Number(e.target.value))}
          {...props}
        />
      </div>
    </div>
  );
}
