import * as React from "react";
import { cx } from "../utils";
import { Sort } from "../icons";

export interface Column<T> {
  key: string;
  header: React.ReactNode;
  /** Cell renderer. Receives the row. */
  cell: (row: T) => React.ReactNode;
  sortable?: boolean;
  /** Comparator used when this column is sorted. */
  sortValue?: (row: T) => string | number;
  width?: string;
  align?: "left" | "right" | "center";
}

export interface TableProps<T> {
  columns: Column<T>[];
  data: T[];
  rowKey: (row: T, index: number) => React.Key;
  className?: string;
}

/**
 * Data-driven table with optional client-side sorting.
 * @example
 * <Table rowKey={(r) => r.id} data={members} columns={[
 *   { key: "name", header: "Member", cell: (r) => r.name, sortable: true, sortValue: (r) => r.name },
 *   { key: "role", header: "Role", cell: (r) => r.role },
 * ]} />
 */
export function Table<T>({ columns, data, rowKey, className }: TableProps<T>) {
  const [sort, setSort] = React.useState<{ key: string; dir: "asc" | "desc" } | null>(null);

  const sorted = React.useMemo(() => {
    if (!sort) return data;
    const col = columns.find((c) => c.key === sort.key);
    if (!col?.sortValue) return data;
    const next = [...data].sort((a, b) => {
      const va = col.sortValue!(a);
      const vb = col.sortValue!(b);
      if (va < vb) return sort.dir === "asc" ? -1 : 1;
      if (va > vb) return sort.dir === "asc" ? 1 : -1;
      return 0;
    });
    return next;
  }, [data, columns, sort]);

  const onSort = (col: Column<T>) => {
    if (!col.sortable) return;
    setSort((prev) =>
      prev?.key === col.key
        ? { key: col.key, dir: prev.dir === "asc" ? "desc" : "asc" }
        : { key: col.key, dir: "asc" },
    );
  };

  return (
    <div className={cx("pui-table-wrap", className)}>
      <table className="pui-table">
        <thead>
          <tr>
            {columns.map((col) => (
              <th
                key={col.key}
                data-sortable={col.sortable || undefined}
                onClick={() => onSort(col)}
                style={{ width: col.width, textAlign: col.align }}
              >
                {col.sortable ? (
                  <span className="pui-table__sort">
                    {col.header}
                    <Sort style={{ width: 13, height: 13 }} />
                  </span>
                ) : (
                  col.header
                )}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.map((row, i) => (
            <tr key={rowKey(row, i)}>
              {columns.map((col) => (
                <td key={col.key} style={{ textAlign: col.align }}>
                  {col.cell(row)}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
