import * as React from "react";
import { cx } from "../utils";
import { Info, CheckCircle, AlertTriangle, XCircle, X } from "../icons";

export type AlertTone = "info" | "success" | "warning" | "danger";

const ICONS: Record<AlertTone, React.ComponentType<React.SVGProps<SVGSVGElement>>> = {
  info: Info,
  success: CheckCircle,
  warning: AlertTriangle,
  danger: XCircle,
};

export interface AlertProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  tone?: AlertTone;
  title?: React.ReactNode;
  onDismiss?: () => void;
}

/** Inline banner for four intents. */
export function Alert({ tone = "info", title, onDismiss, className, children, ...props }: AlertProps) {
  const Icon = ICONS[tone];
  return (
    <div className={cx("pui-alert", className)} data-tone={tone === "info" ? undefined : tone} role="alert" {...props}>
      <Icon className="pui-alert__icon" />
      <div style={{ flex: 1 }}>
        {title && <div className="pui-alert__title">{title}</div>}
        {children && <div className="pui-alert__body">{children}</div>}
      </div>
      {onDismiss && (
        <button type="button" className="pui-alert__close" aria-label="Dismiss" onClick={onDismiss}>
          <X style={{ width: 16, height: 16 }} />
        </button>
      )}
    </div>
  );
}
