import * as React from "react";
import { CheckCircle, XCircle, Info, X } from "../icons";

export type ToastTone = "info" | "success" | "danger";

export interface ToastOptions {
  title: React.ReactNode;
  description?: React.ReactNode;
  tone?: ToastTone;
  /** Auto-dismiss after this many ms. Default 4500. 0 = sticky. */
  duration?: number;
}

interface ToastItem extends ToastOptions {
  id: number;
}

interface ToastContextValue {
  toast: (opts: ToastOptions) => number;
  dismiss: (id: number) => void;
}

const ToastContext = React.createContext<ToastContextValue | null>(null);

const ICONS = { info: Info, success: CheckCircle, danger: XCircle };

/** Wrap your app once; call notifications with the `useToast()` hook. */
export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [items, setItems] = React.useState<ToastItem[]>([]);
  const timers = React.useRef<Record<number, ReturnType<typeof setTimeout>>>({});

  const dismiss = React.useCallback((id: number) => {
    setItems((prev) => prev.filter((t) => t.id !== id));
    if (timers.current[id]) {
      clearTimeout(timers.current[id]);
      delete timers.current[id];
    }
  }, []);

  const toast = React.useCallback(
    (opts: ToastOptions) => {
      const id = Date.now() + Math.random();
      setItems((prev) => [...prev, { id, ...opts }]);
      const duration = opts.duration ?? 4500;
      if (duration > 0) timers.current[id] = setTimeout(() => dismiss(id), duration);
      return id;
    },
    [dismiss],
  );

  React.useEffect(() => () => Object.values(timers.current).forEach(clearTimeout), []);

  return (
    <ToastContext.Provider value={{ toast, dismiss }}>
      {children}
      <div className="pui-toast-region" role="region" aria-label="Notifications">
        {items.map((t) => {
          const Icon = ICONS[t.tone ?? "info"];
          return (
            <div key={t.id} className="pui-toast">
              <span className="pui-toast__icon" data-tone={t.tone ?? "info"}>
                <Icon />
              </span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div className="pui-toast__title">{t.title}</div>
                {t.description && <div className="pui-toast__desc">{t.description}</div>}
              </div>
              <button className="pui-toast__close" aria-label="Dismiss" onClick={() => dismiss(t.id)}>
                <X style={{ width: 15, height: 15 }} />
              </button>
            </div>
          );
        })}
      </div>
    </ToastContext.Provider>
  );
}

export function useToast(): ToastContextValue {
  const ctx = React.useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used within a <ToastProvider>");
  return ctx;
}
