import * as React from "react";
import { cx } from "../utils";
import { ChevronRight, ChevronLeft } from "../icons";

/* ============================================================
   Breadcrumbs
   ============================================================ */
export interface Crumb {
  label: React.ReactNode;
  href?: string;
}
export function Breadcrumbs({ items, className }: { items: Crumb[]; className?: string }) {
  return (
    <nav aria-label="Breadcrumb" className={cx("pui-breadcrumbs", className)}>
      {items.map((c, i) => {
        const last = i === items.length - 1;
        return (
          <React.Fragment key={i}>
            {last || !c.href ? (
              <span className={last ? "pui-breadcrumbs__current" : undefined} aria-current={last ? "page" : undefined}>
                {c.label}
              </span>
            ) : (
              <a href={c.href}>{c.label}</a>
            )}
            {!last && <ChevronRight className="pui-breadcrumbs__sep" />}
          </React.Fragment>
        );
      })}
    </nav>
  );
}

/* ============================================================
   Pagination
   ============================================================ */
export interface PaginationProps {
  page: number;
  count: number;
  onChange: (page: number) => void;
  /** How many sibling pages to show around the current one. Default 1. */
  siblings?: number;
  className?: string;
}

function range(start: number, end: number) {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

export function Pagination({ page, count, onChange, siblings = 1, className }: PaginationProps) {
  const pages = React.useMemo<(number | "…")[]>(() => {
    const total = count;
    const left = Math.max(2, page - siblings);
    const right = Math.min(total - 1, page + siblings);
    const out: (number | "…")[] = [1];
    if (left > 2) out.push("…");
    out.push(...range(left, right));
    if (right < total - 1) out.push("…");
    if (total > 1) out.push(total);
    return out.filter((v, i, a) => v !== a[i - 1]);
  }, [page, count, siblings]);

  return (
    <nav className={cx("pui-pagination", className)} aria-label="Pagination">
      <button className="pui-pagination__btn" disabled={page <= 1} onClick={() => onChange(page - 1)}>
        <ChevronLeft />
        Prev
      </button>
      {pages.map((p, i) =>
        p === "…" ? (
          <span key={`e${i}`} className="pui-pagination__ellipsis">
            …
          </span>
        ) : (
          <button
            key={p}
            className="pui-pagination__btn"
            data-active={p === page || undefined}
            aria-current={p === page ? "page" : undefined}
            onClick={() => onChange(p)}
          >
            {p}
          </button>
        ),
      )}
      <button className="pui-pagination__btn" disabled={page >= count} onClick={() => onChange(page + 1)}>
        Next
        <ChevronRight />
      </button>
    </nav>
  );
}

/* ============================================================
   Segmented control
   ============================================================ */
export interface SegmentedProps {
  options: Array<{ label: React.ReactNode; value: string }>;
  value: string;
  onValueChange: (value: string) => void;
  className?: string;
}
export function Segmented({ options, value, onValueChange, className }: SegmentedProps) {
  return (
    <div className={cx("pui-segmented", className)} role="tablist">
      {options.map((o) => (
        <button
          key={o.value}
          type="button"
          role="tab"
          aria-selected={value === o.value}
          data-active={value === o.value || undefined}
          className="pui-segmented__btn"
          onClick={() => onValueChange(o.value)}
        >
          {o.label}
        </button>
      ))}
    </div>
  );
}
